function findMax(numbers) {
  // Handle empty array
  if (numbers.length === 0) {
    return null;
  }

  // Start with the first element as max
  let max = numbers[0];

  // Iterate through the rest of the array
  for (let i = 1; i < numbers.length; i++) {
    if (numbers[i] > max) {
      max = numbers[i];
    }
  }

  return max;
}
